"""Graph utilities module for common graph algorithms."""

from collections import deque
from typing import Dict, List, Optional, Set


def has_cycle(adj_list: Dict) -> bool:
    """
    Detect if a directed graph has a cycle using DFS with color marking.

    Args:
        adj_list: dict mapping node -> list of neighbors

    Returns:
        True if the graph has a cycle, False otherwise
    """
    # Color: 0 = white (unvisited), 1 = gray (visiting), 2 = black (visited)
    color = {}

    def dfs(node):
        """Helper function to perform DFS and detect cycles."""
        color[node] = 1  # Mark as gray (visiting)

        # Visit all neighbors
        neighbors = adj_list.get(node, [])
        for neighbor in neighbors:
            if neighbor not in color:
                # Unvisited node, continue DFS
                if dfs(neighbor):
                    return True
            elif color[neighbor] == 1:
                # Found a back edge (gray node), cycle detected
                return True

        color[node] = 2  # Mark as black (visited)
        return False

    # Check all nodes in the graph
    for node in adj_list:
        if node not in color:
            if dfs(node):
                return True

    return False


def shortest_path(adj_list: Dict, start, end) -> Optional[List]:
    """
    Find the shortest path between two nodes in an unweighted graph using BFS.

    Args:
        adj_list: dict mapping node -> list of neighbors
        start: starting node
        end: ending node

    Returns:
        List of nodes representing the shortest path, or None if no path exists
    """
    if start == end:
        return [start]

    visited = {start}
    queue = deque([(start, [start])])

    while queue:
        node, path = queue.popleft()

        neighbors = adj_list.get(node, [])
        for neighbor in neighbors:
            if neighbor == end:
                return path + [neighbor]

            if neighbor not in visited:
                visited.add(neighbor)
                queue.append((neighbor, path + [neighbor]))

    return None


def topological_sort(adj_list: Dict) -> Optional[List]:
    """
    Return topological ordering of a directed acyclic graph (DAG).

    Args:
        adj_list: dict mapping node -> list of neighbors

    Returns:
        List representing a valid topological ordering, or None if cycle exists
    """
    # First check if the graph has a cycle
    if has_cycle(adj_list):
        return None

    # Kahn's algorithm using in-degree
    in_degree = {}

    # Initialize in-degree for all nodes
    for node in adj_list:
        if node not in in_degree:
            in_degree[node] = 0

    # Count in-degrees
    for node in adj_list:
        for neighbor in adj_list.get(node, []):
            if neighbor not in in_degree:
                in_degree[neighbor] = 0
            in_degree[neighbor] += 1

    # Queue of nodes with in-degree 0
    queue = deque([node for node in in_degree if in_degree[node] == 0])
    result = []

    while queue:
        node = queue.popleft()
        result.append(node)

        # Remove edges from this node
        for neighbor in adj_list.get(node, []):
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    # All nodes should be processed if there's no cycle
    if len(result) == len(in_degree):
        return result
    else:
        return None

"""Graph utilities for directed graphs."""

from collections import deque
from typing import Dict, List, Optional


def has_cycle(adj_list: Dict) -> bool:
    """
    Detect if a directed graph has a cycle.

    Args:
        adj_list: Dictionary mapping node to list of neighbors

    Returns:
        True if the graph has a cycle, False otherwise
    """
    # Colors: 0 = white (unvisited), 1 = gray (visiting), 2 = black (visited)
    colors = {}

    def has_cycle_dfs(node):
        """DFS helper to detect cycles."""
        colors[node] = 1  # Mark as visiting (gray)

        for neighbor in adj_list.get(node, []):
            if neighbor not in colors:
                if has_cycle_dfs(neighbor):
                    return True
            elif colors[neighbor] == 1:  # Back edge found (cycle)
                return True

        colors[node] = 2  # Mark as visited (black)
        return False

    # Check all nodes for cycles
    for node in adj_list:
        if node not in colors:
            if has_cycle_dfs(node):
                return True

    return False


def shortest_path(
    adj_list: Dict, start: str, end: str
) -> Optional[List[str]]:
    """
    Find the shortest path in an unweighted directed graph using BFS.

    Args:
        adj_list: Dictionary mapping node to list of neighbors
        start: Starting node
        end: Ending node

    Returns:
        List of nodes representing the shortest path, or None if no path exists
    """
    if start == end:
        return [start]

    visited = {start}
    queue = deque([(start, [start])])

    while queue:
        node, path = queue.popleft()

        for neighbor in adj_list.get(node, []):
            if neighbor == end:
                return path + [neighbor]

            if neighbor not in visited:
                visited.add(neighbor)
                queue.append((neighbor, path + [neighbor]))

    return None


def topological_sort(adj_list: Dict) -> Optional[List]:
    """
    Perform topological sorting on a directed acyclic graph (DAG).

    Args:
        adj_list: Dictionary mapping node to list of neighbors

    Returns:
        List of nodes in topological order, or None if the graph has a cycle
    """
    if has_cycle(adj_list):
        return None

    # Kahn's algorithm using in-degree
    in_degree = {}

    # Initialize in-degrees
    for node in adj_list:
        if node not in in_degree:
            in_degree[node] = 0

    for node in adj_list:
        for neighbor in adj_list.get(node, []):
            if neighbor not in in_degree:
                in_degree[neighbor] = 0
            in_degree[neighbor] += 1

    # Find all nodes with in-degree 0
    queue = deque([node for node in in_degree if in_degree[node] == 0])
    result = []

    while queue:
        node = queue.popleft()
        result.append(node)

        for neighbor in adj_list.get(node, []):
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    return result

