import pytest
from graph import has_cycle, shortest_path, topological_sort


class TestHasCycle:
    """Test cycle detection in directed graphs."""

    def test_empty_graph(self):
        """Empty graph has no cycle."""
        assert has_cycle({}) is False

    def test_single_node_no_cycle(self):
        """Single node without self-loop has no cycle."""
        assert has_cycle({"A": []}) is False

    def test_single_node_self_loop(self):
        """Single node with self-loop is a cycle."""
        assert has_cycle({"A": ["A"]}) is True

    def test_simple_linear_graph(self):
        """Linear path A->B->C has no cycle."""
        graph = {"A": ["B"], "B": ["C"], "C": []}
        assert has_cycle(graph) is False

    def test_simple_cycle(self):
        """Simple cycle A->B->A should be detected."""
        graph = {"A": ["B"], "B": ["A"]}
        assert has_cycle(graph) is True

    def test_longer_cycle(self):
        """Longer cycle A->B->C->A should be detected."""
        graph = {"A": ["B"], "B": ["C"], "C": ["A"]}
        assert has_cycle(graph) is True

    def test_complex_dag(self):
        """Complex DAG should have no cycle."""
        graph = {
            "A": ["B", "C"],
            "B": ["D"],
            "C": ["D"],
            "D": [],
        }
        assert has_cycle(graph) is False

    def test_complex_with_cycle(self):
        """Complex graph with cycle should be detected."""
        graph = {
            "A": ["B", "C"],
            "B": ["D"],
            "C": ["D"],
            "D": ["B"],  # Creates cycle B->D->B
        }
        assert has_cycle(graph) is True

    def test_multiple_components_no_cycle(self):
        """Multiple disconnected components without cycles."""
        graph = {
            "A": ["B"],
            "B": [],
            "C": ["D"],
            "D": [],
        }
        assert has_cycle(graph) is False

    def test_multiple_components_with_cycle(self):
        """Multiple disconnected components, one has a cycle."""
        graph = {
            "A": ["B"],
            "B": [],
            "C": ["D"],
            "D": ["C"],  # Cycle in second component
        }
        assert has_cycle(graph) is True


class TestShortestPath:
    """Test shortest path finding using BFS."""

    def test_same_start_and_end(self):
        """Path from node to itself."""
        graph = {"A": []}
        assert shortest_path(graph, "A", "A") == ["A"]

    def test_direct_edge(self):
        """Direct edge from start to end."""
        graph = {"A": ["B"], "B": []}
        assert shortest_path(graph, "A", "B") == ["A", "B"]

    def test_linear_path(self):
        """Linear path A->B->C."""
        graph = {"A": ["B"], "B": ["C"], "C": []}
        assert shortest_path(graph, "A", "C") == ["A", "B", "C"]

    def test_no_path(self):
        """No path exists between nodes."""
        graph = {"A": ["B"], "B": [], "C": []}
        assert shortest_path(graph, "A", "C") is None

    def test_shortest_among_multiple_paths(self):
        """Choose shortest path when multiple exist."""
        graph = {
            "A": ["B", "C"],
            "B": ["D"],
            "C": ["D"],
            "D": [],
        }
        # Both A->B->D and A->C->D are valid paths of length 3
        result = shortest_path(graph, "A", "D")
        assert result is not None
        assert len(result) == 3
        assert result[0] == "A"
        assert result[-1] == "D"

    def test_complex_graph(self):
        """Path in more complex graph."""
        graph = {
            "A": ["B", "C"],
            "B": ["D"],
            "C": ["E"],
            "D": ["F"],
            "E": ["F"],
            "F": [],
        }
        result = shortest_path(graph, "A", "F")
        assert result is not None
        assert result[0] == "A"
        assert result[-1] == "F"
        # Should be one of: A->B->D->F or A->C->E->F (length 4)
        assert len(result) == 4

    def test_nonexistent_nodes(self):
        """Path involving non-existent nodes."""
        graph = {"A": ["B"], "B": []}
        assert shortest_path(graph, "X", "Y") is None
        assert shortest_path(graph, "A", "X") is None

    def test_empty_graph(self):
        """Empty graph returns None for any path."""
        graph = {}
        assert shortest_path(graph, "A", "B") is None

    def test_single_node(self):
        """Single node path."""
        graph = {"A": []}
        assert shortest_path(graph, "A", "A") == ["A"]
        assert shortest_path(graph, "A", "B") is None


class TestTopologicalSort:
    """Test topological sorting of DAGs."""

    def test_empty_graph(self):
        """Empty graph returns empty list."""
        result = topological_sort({})
        assert result == []

    def test_single_node(self):
        """Single node sorts to itself."""
        graph = {"A": []}
        result = topological_sort(graph)
        assert result == ["A"]

    def test_linear_dag(self):
        """Linear DAG A->B->C."""
        graph = {"A": ["B"], "B": ["C"], "C": []}
        result = topological_sort(graph)
        assert result is not None
        assert result == ["A", "B", "C"]

    def test_simple_dag(self):
        """Simple DAG with multiple paths."""
        graph = {
            "A": ["B", "C"],
            "B": ["D"],
            "C": ["D"],
            "D": [],
        }
        result = topological_sort(graph)
        assert result is not None
        # A must come before B and C
        assert result.index("A") < result.index("B")
        assert result.index("A") < result.index("C")
        # B and C must come before D
        assert result.index("B") < result.index("D")
        assert result.index("C") < result.index("D")

    def test_complex_dag(self):
        """More complex DAG."""
        graph = {
            "5": ["2", "0"],
            "4": ["0", "1"],
            "2": ["3"],
            "3": ["1"],
            "1": [],
            "0": [],
        }
        result = topological_sort(graph)
        assert result is not None
        # Check ordering constraints
        assert result.index("5") < result.index("2")
        assert result.index("5") < result.index("0")
        assert result.index("4") < result.index("0")
        assert result.index("4") < result.index("1")
        assert result.index("2") < result.index("3")
        assert result.index("3") < result.index("1")

    def test_simple_cycle_returns_none(self):
        """Graph with cycle returns None."""
        graph = {"A": ["B"], "B": ["A"]}
        assert topological_sort(graph) is None

    def test_self_loop_returns_none(self):
        """Graph with self-loop returns None."""
        graph = {"A": ["A"]}
        assert topological_sort(graph) is None

    def test_complex_cycle_returns_none(self):
        """Complex graph with cycle returns None."""
        graph = {
            "A": ["B"],
            "B": ["C"],
            "C": ["D"],
            "D": ["B"],  # Cycle B->C->D->B
        }
        assert topological_sort(graph) is None

    def test_disconnected_components(self):
        """DAG with disconnected components."""
        graph = {
            "A": ["B"],
            "B": [],
            "C": ["D"],
            "D": [],
        }
        result = topological_sort(graph)
        assert result is not None
        assert set(result) == {"A", "B", "C", "D"}
        # Check valid ordering within components
        assert result.index("A") < result.index("B")
        assert result.index("C") < result.index("D")

    def test_result_length(self):
        """Topological sort returns all nodes."""
        graph = {
            "A": ["B", "C"],
            "B": ["D"],
            "C": ["D"],
            "D": [],
        }
        result = topological_sort(graph)
        assert result is not None
        assert len(result) == 4
        assert set(result) == {"A", "B", "C", "D"}


if __name__ == "__main__":
    pytest.main([__file__, "-v"])

