class TestShortestPath:
    """Tests for shortest_path function."""

    def test_direct_edge(self):
        """Direct edge A -> B should return [A, B]."""
        graph = {"A": ["B"], "B": []}
        assert shortest_path(graph, "A", "B") == ["A", "B"]

    def test_single_node_to_itself(self):
        """Path from node to itself should return [node]."""
        graph = {"A": []}
        assert shortest_path(graph, "A", "A") == ["A"]

