        """Linear path A -> B -> C -> D should return [A, B, C, D]."""
        graph = {
            "A": ["B"],
            "B": ["C"],
            "C": ["D"],
            "D": [],
        }
        assert shortest_path(graph, "A", "D") == ["A", "B", "C", "D"]

    def test_multiple_paths_shortest(self):
        """With multiple paths, should return shortest."""
        # Path 1: A -> B -> D (length 2)
        # Path 2: A -> C -> D (length 2)
        # Path 3: A -> B -> C -> D (length 3)
        graph = {
            "A": ["B", "C"],
            "B": ["D", "C"],
            "C": ["D"],
            "D": [],
        }
        path = shortest_path(graph, "A", "D")
        assert path in (["A", "B", "D"], ["A", "C", "D"])
        assert len(path) == 3

