        """When no path exists, should return None."""
        graph = {
            "A": ["B"],
            "B": [],
            "C": ["D"],
            "D": [],
        }
        assert shortest_path(graph, "A", "C") is None

    def test_start_not_in_graph(self):
        """When start node not in graph, should return None."""
        graph = {"A": ["B"], "B": []}
        assert shortest_path(graph, "Z", "B") is None

    def test_end_not_in_graph(self):
        """When end node not in graph, should return None."""
        graph = {"A": ["B"], "B": []}
        assert shortest_path(graph, "A", "Z") is None

    def test_both_nodes_not_in_graph(self):
        """When both nodes not in graph, should return None."""
        graph = {"A": ["B"], "B": []}
        assert shortest_path(graph, "X", "Z") is None

    def test_diamond_graph(self):
        """Diamond shape should find shortest path."""
        graph = {
            "A": ["B", "C"],
            "B": ["D"],
            "C": ["D"],
            "D": [],
        }
        path = shortest_path(graph, "A", "D")
        assert path == ["A", "B", "D"] or path == ["A", "C", "D"]
        assert len(path) == 3

