        """Complex graph with various paths."""
        graph = {
            "A": ["B"],
            "B": ["C"],
            "C": ["D", "E"],
            "D": ["F"],
            "E": ["F"],
            "F": [],
        }
        path = shortest_path(graph, "A", "F")
        assert path == ["A", "B", "C", "D", "F"] or path == ["A", "B", "C", "E", "F"]
