class TestTopologicalSort:
    """Tests for topological_sort function."""

    def test_empty_graph(self):
        """Empty graph should return empty list."""
        assert topological_sort({}) == []

    def test_single_node(self):
        """Single node should return list with that node."""
        result = topological_sort({"A": []})
        assert result == ["A"]

    def test_linear_chain(self):
        """Linear chain A -> B -> C should be sorted correctly."""
        graph = {"A": ["B"], "B": ["C"], "C": []}
        result = topological_sort(graph)
        assert result == ["A", "B", "C"]

    def test_simple_dag(self):
        """Simple DAG should be sorted topologically."""
        graph = {
            "A": ["B", "C"],
            "B": ["D"],
            "C": ["D"],
            "D": [],
        }
        result = topological_sort(graph)
        # Check that A comes before B and C, and B, C come before D
        assert result.index("A") < result.index("B")
        assert result.index("A") < result.index("C")
        assert result.index("B") < result.index("D")
        assert result.index("C") < result.index("D")

