        """Self-loop should be detected as cycle."""
        graph = {"A": ["A"], "B": []}
        assert topological_sort(graph) is None

    def test_simple_two_node_cycle(self):
        """Two-node cycle should be detected."""
        graph = {"A": ["B"], "B": ["A"]}
        assert topological_sort(graph) is None

