        """Disconnected graph with no cycles should be sorted."""
        graph = {
            "A": ["B"],
            "B": [],
            "C": ["D"],
            "D": [],
        }
        result = topological_sort(graph)
        assert len(result) == 4
        assert result.index("A") < result.index("B")
        assert result.index("C") < result.index("D")

    def test_multiple_sources(self):
        """Graph with multiple source nodes (in-degree 0)."""
        graph = {
            "A": ["D"],
            "B": ["D"],
            "C": ["D"],
            "D": [],
        }
        result = topological_sort(graph)
        assert len(result) == 4
        assert result[-1] == "D"

