        graph = {
            "A": ["B", "C"],
            "B": ["D"],
            "C": ["D", "E"],
            "D": ["F"],
            "E": ["F"],
            "F": [],
        }
        result = topological_sort(graph)
        # Check all dependencies
        assert result.index("A") < result.index("B")
        assert result.index("A") < result.index("C")
        assert result.index("B") < result.index("D")
        assert result.index("C") < result.index("D")
        assert result.index("C") < result.index("E")
        assert result.index("D") < result.index("F")
        assert result.index("E") < result.index("F")

    def test_cycle_in_complex_graph(self):
        """Cycle in complex graph should be detected."""
        graph = {
            "A": ["B", "C"],
            "B": ["D"],
            "C": ["D"],
            "D": ["E"],
            "E": ["B"],  # Creates cycle: B -> D -> E -> B
        }
        assert topological_sort(graph) is None

    def test_single_node_no_edge(self):
        """Single node with no edges."""
        result = topological_sort({"X": []})
        assert result == ["X"]

def tokenize(expr):
    """
    Convert a math expression string to a list of tokens.

    Token types:
    - NUMBER: {"type": "NUMBER", "value": 42} or {"type": "NUMBER", "value": 3.14}
    - OPERATOR: {"type": "OPERATOR", "value": "+"} etc.
    - LPAREN: {"type": "LPAREN"}
    - RPAREN: {"type": "RPAREN"}

    Handles:
    - Whitespace (ignored)
    - Negative numbers (-3)
    - Decimal numbers (3.14)

    Raises ValueError on invalid characters.
    """
    tokens = []
    i = 0

    while i < len(expr):
        char = expr[i]

        # Skip whitespace
        if char.isspace():
            i += 1
            continue

        # Handle numbers (including negative numbers)
        if char.isdigit() or (char == '-' and i + 1 < len(expr) and expr[i + 1].isdigit()):
            # Check if '-' is actually a negative sign or operator
            if char == '-':
                # It's a negative number if:
                # 1. We're at the start, or
                # 2. Previous token was an operator or LPAREN
                if len(tokens) == 0 or tokens[-1]["type"] in ("OPERATOR", "LPAREN"):
                    # Parse negative number
                    j = i + 1
                    while j < len(expr) and (expr[j].isdigit() or expr[j] == '.'):
                        j += 1
                    num_str = expr[i:j]
                    try:
                        if '.' in num_str:
                            value = float(num_str)
                        else:
                            value = int(num_str)
                        tokens.append({"type": "NUMBER", "value": value})
                        i = j
                        continue
                    except ValueError:
                        raise ValueError(f"Invalid number: {num_str}")

            # Parse positive number
            j = i
            while j < len(expr) and (expr[j].isdigit() or expr[j] == '.'):
                j += 1
            num_str = expr[i:j]
            try:
                if '.' in num_str:
                    value = float(num_str)
                else:
                    value = int(num_str)
                tokens.append({"type": "NUMBER", "value": value})
                i = j
            except ValueError:
                raise ValueError(f"Invalid number: {num_str}")

        # Handle operators
        elif char in ('+', '-', '*', '/'):
            tokens.append({"type": "OPERATOR", "value": char})
            i += 1

        # Handle parentheses
        elif char == '(':
            tokens.append({"type": "LPAREN"})
            i += 1
        elif char == ')':
            tokens.append({"type": "RPAREN"})
            i += 1

        # Invalid character
        else:
            raise ValueError(f"Invalid character: '{char}'")

    return tokens

