import pytest
from csv_parser import parse_csv, to_csv


class TestParseCSV:
    """Test parse_csv function."""

    def test_simple_csv(self):
        """Test parsing simple CSV with no special characters."""
        csv_text = "name,age,city\nAlice,30,NYC\nBob,25,LA"
        result = parse_csv(csv_text)

        assert len(result) == 2
        assert result[0] == {"name": "Alice", "age": "30", "city": "NYC"}
        assert result[1] == {"name": "Bob", "age": "25", "city": "LA"}

    def test_empty_input(self):
        """Test parsing empty string returns empty list."""
        assert parse_csv("") == []
        assert parse_csv("   ") == []

    def test_header_only(self):
        """Test parsing CSV with only header."""
        csv_text = "name,age,city"
        result = parse_csv(csv_text)
        assert result == []

    def test_quoted_fields(self):
        """Test parsing quoted fields."""
        csv_text = 'name,description\nAlice,"A nice person"\nBob,"Another person"'
        result = parse_csv(csv_text)

        assert len(result) == 2
        assert result[0] == {"name": "Alice", "description": "A nice person"}
        assert result[1] == {"name": "Bob", "description": "Another person"}

    def test_quoted_field_with_comma(self):
        """Test parsing quoted field containing a comma."""
        csv_text = 'name,address\nAlice,"123 Main St, Apt 4"\nBob,"456 Oak Ave, Suite 100"'
        result = parse_csv(csv_text)

        assert len(result) == 2
        assert result[0] == {"name": "Alice", "address": "123 Main St, Apt 4"}
        assert result[1] == {"name": "Bob", "address": "456 Oak Ave, Suite 100"}

    def test_escaped_quotes(self):
        """Test parsing escaped quotes inside quoted fields."""
        csv_text = 'name,comment\nAlice,"She said ""hello"""\nBob,"He replied ""hi"""'
        result = parse_csv(csv_text)

        assert len(result) == 2
        assert result[0] == {"name": "Alice", "comment": 'She said "hello"'}
        assert result[1] == {"name": "Bob", "comment": 'He replied "hi"'}

    def test_empty_fields(self):
        """Test parsing empty fields."""
        csv_text = "name,age,city\nAlice,30,\nBob,,LA"
        result = parse_csv(csv_text)

        assert len(result) == 2
        assert result[0] == {"name": "Alice", "age": "30", "city": ""}
        assert result[1] == {"name": "Bob", "age": "", "city": "LA"}

    def test_newline_in_quoted_field(self):
        """Test parsing newlines inside quoted fields."""
        csv_text = 'name,bio\nAlice,"Line 1\nLine 2"\nBob,"Bio1\nBio2\nBio3"'
        result = parse_csv(csv_text)

        assert len(result) == 2
        assert result[0] == {"name": "Alice", "bio": "Line 1\nLine 2"}
        assert result[1] == {"name": "Bob", "bio": "Bio1\nBio2\nBio3"}

    def test_quoted_field_with_comma_and_newline(self):
        """Test parsing quoted field with both comma and newline."""
        csv_text = 'name,address\nAlice,"123 Main St,\nApt 4"\nBob,"456 Oak Ave, Suite 100"'
        result = parse_csv(csv_text)

        assert len(result) == 2
        assert result[0] == {"name": "Alice", "address": "123 Main St,\nApt 4"}
        assert result[1] == {"name": "Bob", "address": "456 Oak Ave, Suite 100"}

    def test_quoted_field_with_comma_and_escaped_quote(self):
        """Test parsing quoted field with comma and escaped quote."""
        csv_text = 'name,comment\nAlice,"She said ""hello"", great!"\nBob,normal'
        result = parse_csv(csv_text)

        assert len(result) == 2
        assert result[0] == {"name": "Alice", "comment": 'She said "hello", great!'}
        assert result[1] == {"name": "Bob", "comment": "normal"}

    def test_single_field(self):
        """Test parsing CSV with single column."""
        csv_text = "name\nAlice\nBob\nCharlie"
        result = parse_csv(csv_text)

        assert len(result) == 3
        assert result[0] == {"name": "Alice"}
        assert result[1] == {"name": "Bob"}
        assert result[2] == {"name": "Charlie"}

    def test_quoted_empty_field(self):
        """Test parsing quoted empty field."""
        csv_text = 'name,comment\nAlice,""\nBob,hello'
        result = parse_csv(csv_text)

        assert len(result) == 2
        assert result[0] == {"name": "Alice", "comment": ""}
        assert result[1] == {"name": "Bob", "comment": "hello"}

    def test_fields_with_whitespace(self):
        """Test that whitespace is preserved."""
        csv_text = "name,comment\nAlice,  spaced  \nBob, leading"
        result = parse_csv(csv_text)

        assert len(result) == 2
        assert result[0] == {"name": "Alice", "comment": "  spaced  "}
        assert result[1] == {"name": "Bob", "comment": " leading"}

    def test_skip_empty_lines(self):
        """Test that empty lines are skipped."""
        csv_text = "name,age\nAlice,30\n\nBob,25"
        result = parse_csv(csv_text)

        assert len(result) == 2
        assert result[0] == {"name": "Alice", "age": "30"}
        assert result[1] == {"name": "Bob", "age": "25"}

    def test_fewer_fields_than_header(self):
        """Test row with fewer fields than header."""
        csv_text = "name,age,city\nAlice,30\nBob,25,LA"
        result = parse_csv(csv_text)

        assert len(result) == 2
        assert result[0] == {"name": "Alice", "age": "30", "city": ""}
        assert result[1] == {"name": "Bob", "age": "25", "city": "LA"}

    def test_more_fields_than_header(self):
        """Test row with more fields than header."""
        csv_text = "name,age\nAlice,30,NYC,USA\nBob,25,LA"
        result = parse_csv(csv_text)

        assert len(result) == 2
        assert result[0] == {"name": "Alice", "age": "30"}
        assert result[1] == {"name": "Bob", "age": "25"}


