"""Tests for CSV Parser module."""

import pytest
from csv_parser import parse_csv, to_csv


class TestParseCSV:
    """Tests for parse_csv function."""

    def test_simple_csv(self):
        """Test parsing simple CSV without special characters."""
        csv_text = "name,age,city\nAlice,30,NYC\nBob,25,LA"
        result = parse_csv(csv_text)
        assert len(result) == 2
        assert result[0] == {'name': 'Alice', 'age': '30', 'city': 'NYC'}
        assert result[1] == {'name': 'Bob', 'age': '25', 'city': 'LA'}

    def test_quoted_fields(self):
        """Test parsing CSV with quoted fields."""
        csv_text = 'name,description\nAlice,"Engineer, Manager"\nBob,"Designer"'
        result = parse_csv(csv_text)
        assert len(result) == 2
        assert result[0] == {'name': 'Alice', 'description': 'Engineer, Manager'}
        assert result[1] == {'name': 'Bob', 'description': 'Designer'}

    def test_escaped_quotes(self):
