import pytest
from interval import merge_intervals, insert_interval, can_attend_all


class TestMergeIntervals:
    """Test merge_intervals function"""

    def test_empty_list(self):
        """Empty interval list should return empty list"""
        assert merge_intervals([]) == []

    def test_single_interval(self):
        """Single interval should return as-is"""
        assert merge_intervals([[1, 5]]) == [[1, 5]]

    def test_no_overlap(self):
        """Non-overlapping intervals should remain in order"""
        assert merge_intervals([[1, 2], [3, 4], [5, 6]]) == [[1, 2], [3, 4], [5, 6]]

    def test_overlapping_two_intervals(self):
        """Two overlapping intervals should merge"""
        assert merge_intervals([[1, 4], [2, 5]]) == [[1, 5]]

    def test_one_contains_another(self):
        """Smaller interval contained in larger should merge"""
        assert merge_intervals([[1, 5], [2, 3]]) == [[1, 5]]

    def test_adjacent_intervals(self):
        """Adjacent intervals [1,2] and [2,3] should merge to [1,3]"""
        assert merge_intervals([[1, 2], [2, 3]]) == [[1, 3]]

    def test_multiple_overlaps(self):
        """Multiple overlapping intervals should all merge"""
        assert merge_intervals([[1, 3], [2, 6], [8, 10], [15, 18]]) == [[1, 6], [8, 10], [15, 18]]

    def test_unsorted_input(self):
        """Unsorted intervals should still be merged correctly"""
        assert merge_intervals([[2, 5], [1, 3], [4, 6]]) == [[1, 6]]

    def test_completely_overlapping(self):
        """Completely overlapping intervals should merge"""
        assert merge_intervals([[1, 5], [1, 5], [1, 5]]) == [[1, 5]]

    def test_duplicates(self):
        """Duplicate intervals should merge"""
        assert merge_intervals([[1, 3], [1, 3]]) == [[1, 3]]

    def test_nested_multiple(self):
        """Multiple nested intervals should merge"""
        assert merge_intervals([[1, 10], [2, 4], [5, 7], [3, 6]]) == [[1, 10]]

    def test_zero_length_intervals(self):
        """Zero-length intervals [5, 5] should be handled"""
        assert merge_intervals([[1, 2], [5, 5], [5, 6]]) == [[1, 2], [5, 6]]

    def test_negative_numbers(self):
        """Intervals with negative numbers should merge correctly"""
        assert merge_intervals([[-5, -2], [-3, 1]]) == [[-5, 1]]


class TestInsertInterval:
    """Test insert_interval function"""

    def test_empty_list(self):
        """Inserting into empty list should return single interval"""
