    def test_insert_merge_left(self):
        """Insert interval that merges with left neighbor"""
        assert insert_interval([[1, 5], [6, 8]], [4, 6]) == [[1, 8]]

    def test_insert_merge_right(self):
        """Insert interval that merges with right neighbor"""
