    def test_insert_adjacent_right(self):
        """Insert adjacent to right: [1, 2] + [2, 3] = [1, 3]"""
        assert insert_interval([[1, 2]], [2, 3]) == [[1, 3]]

    def test_insert_single_existing(self):
        """Insert into list with single existing interval"""
