import pytest
from graph import has_cycle, shortest_path, topological_sort


class TestHasCycle:
    """Tests for cycle detection in directed graphs"""

    def test_empty_graph_no_cycle(self):
        """Empty graph has no cycle"""
        assert has_cycle({}) is False

    def test_single_node_no_cycle(self):
        """Single node with no edges has no cycle"""
        assert has_cycle({"A": []}) is False

    def test_self_loop_is_cycle(self):
        """Node pointing to itself is a cycle"""
        assert has_cycle({"A": ["A"]}) is True

    def test_two_nodes_no_cycle(self):
        """Two nodes in linear sequence, no cycle"""
        assert has_cycle({"A": ["B"], "B": []}) is False

    def test_two_nodes_cycle(self):
        """Two nodes forming a cycle"""
        assert has_cycle({"A": ["B"], "B": ["A"]}) is True

    def test_simple_cycle_three_nodes(self):
        """Three nodes forming a cycle"""
        assert has_cycle({"A": ["B"], "B": ["C"], "C": ["A"]}) is True

    def test_three_nodes_no_cycle(self):
        """Three nodes, linear chain, no cycle"""
        assert has_cycle({"A": ["B"], "B": ["C"], "C": []}) is False

    def test_complex_dag_no_cycle(self):
        """Complex directed acyclic graph"""
        graph = {
            "A": ["B", "C"],
            "B": ["D"],
            "C": ["D"],
            "D": []
        }
        assert has_cycle(graph) is False

    def test_complex_graph_with_cycle(self):
        """Complex graph with hidden cycle"""
        graph = {
            "A": ["B", "C"],
            "B": ["D"],
            "C": ["D"],
            "D": ["A"]  # Creates cycle
        }
        assert has_cycle(graph) is True

    def test_isolated_nodes_no_cycle(self):
        """Multiple isolated nodes"""
        graph = {"A": [], "B": [], "C": []}
        assert has_cycle(graph) is False

    def test_multiple_components_with_cycle(self):
        """Multiple connected components, one has cycle"""
        graph = {
            "A": ["B"],
            "B": [],
            "C": ["D"],
            "D": ["C"]  # Cycle in this component
        }
        assert has_cycle(graph) is True


class TestShortestPath:
    """Tests for shortest path finding using BFS"""

    def test_empty_graph_returns_none(self):
        """Empty graph returns None"""
        assert shortest_path({}, "A", "B") is None

    def test_start_equals_end(self):
        """Path from node to itself"""
        graph = {"A": []}
        assert shortest_path(graph, "A", "A") == ["A"]

    def test_direct_edge(self):
        """Direct edge from start to end"""
        graph = {"A": ["B"], "B": []}
        result = shortest_path(graph, "A", "B")
        assert result == ["A", "B"]

    def test_path_not_exists(self):
        """No path exists between nodes"""
        graph = {"A": ["B"], "B": [], "C": []}
        assert shortest_path(graph, "A", "C") is None

    def test_linear_path(self):
        """Linear path through multiple nodes"""
        graph = {
            "A": ["B"],
            "B": ["C"],
            "C": ["D"],
            "D": []
        }
        result = shortest_path(graph, "A", "D")
        assert result == ["A", "B", "C", "D"]

    def test_shortest_among_multiple(self):
        """BFS finds shortest path when multiple exist"""
        graph = {
            "A": ["B", "C"],
            "B": ["D"],
            "C": ["D"],
            "D": []
        }
        result = shortest_path(graph, "A", "D")
        assert len(result) == 3  # 2 edges = 3 nodes
