from collections import deque, defaultdict


def has_cycle(adj_list):
    """
    Detect if a directed graph has a cycle using DFS with color marking.

    Args:
        adj_list: dict mapping node -> list of neighbors

    Returns:
        True if the graph contains a cycle, False otherwise
    """
    if not adj_list:
        return False

    # Color states: 0 = white (unvisited), 1 = gray (visiting), 2 = black (visited)
    color = {}

    def dfs(node):
        """Returns True if a cycle is detected from this node"""
        color[node] = 1  # Mark as gray (visiting)

        for neighbor in adj_list.get(node, []):
            if neighbor not in color:
                # Unvisited node
                if dfs(neighbor):
                    return True
            elif color[neighbor] == 1:
                # Back edge to a node currently being visited (cycle detected)
                return True

        color[node] = 2  # Mark as black (visited)
        return False

    # Check all nodes in case of disconnected components
    for node in adj_list:
        if node not in color:
            if dfs(node):
                return True

    return False


def shortest_path(adj_list, start, end):
    """
    Find the shortest path in an unweighted directed graph using BFS.

    Args:
        adj_list: dict mapping node -> list of neighbors
        start: starting node
        end: ending node

    Returns:
        List of nodes representing the shortest path from start to end,
        or None if no path exists
    """
    if not adj_list:
        return None

    if start not in adj_list:
        return None

    if start == end:
        return [start]

    # BFS
    queue = deque([start])
    visited = {start}
    parent = {start: None}

    while queue:
        current = queue.popleft()

        for neighbor in adj_list.get(current, []):
            if neighbor not in visited:
                visited.add(neighbor)
                parent[neighbor] = current

                if neighbor == end:
                    # Reconstruct path
                    path = []
                    node = end
                    while node is not None:
                        path.append(node)
                        node = parent[node]
                    return path[::-1]

                queue.append(neighbor)

    return None


def topological_sort(adj_list):
    """
    Return a topological ordering of nodes in a directed acyclic graph (DAG).
    Uses Kahn's algorithm (BFS-based with in-degree counting).

    Args:
        adj_list: dict mapping node -> list of neighbors

    Returns:
        List of nodes in topological order, or None if the graph contains a cycle
    """
    if not adj_list:
        return []

    # Calculate in-degrees for all nodes
    in_degree = defaultdict(int)

    # Initialize all nodes with in-degree 0
    for node in adj_list:
        if node not in in_degree:
            in_degree[node] = 0

    # Calculate actual in-degrees
    for node in adj_list:
        for neighbor in adj_list.get(node, []):
            in_degree[neighbor] += 1
            # Ensure neighbor is in the graph even if it has no outgoing edges
            if neighbor not in adj_list:
                adj_list[neighbor] = []

    # Find all nodes with in-degree 0
    queue = deque([node for node in adj_list if in_degree[node] == 0])
    result = []

    while queue:
        # Process node with in-degree 0
        node = queue.popleft()
        result.append(node)

        # Reduce in-degree for all neighbors
        for neighbor in adj_list.get(node, []):
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    # If we processed all nodes, it's a DAG; otherwise, there's a cycle
    if len(result) == len(adj_list):
        return result
    else:
        return None

