"""Graph utilities for cycle detection, shortest path, and topological sorting."""

from collections import deque, defaultdict


def has_cycle(adj_list):
    """
    Detect if a directed graph has a cycle.

    Args:
        adj_list: dict mapping node -> list of neighbors

    Returns:
        bool: True if graph has a cycle, False otherwise
    """
    if not adj_list:
        return False

    # States: 0 = unvisited, 1 = visiting, 2 = visited
    state = {node: 0 for node in adj_list}

    def dfs(node):
        """DFS to detect cycle. Returns True if cycle found."""
        state[node] = 1  # Mark as visiting

        for neighbor in adj_list.get(node, []):
            if neighbor not in state:
                state[neighbor] = 0

            if state[neighbor] == 1:
                # Back edge found - cycle detected
                return True

            if state[neighbor] == 0 and dfs(neighbor):
                return True

        state[node] = 2  # Mark as visited
        return False

    # Check all nodes (for disconnected components)
    for node in adj_list:
        if state[node] == 0:
            if dfs(node):
                return True

    return False


def shortest_path(adj_list, start, end):
    """
    Find shortest path between two nodes using BFS.

    Args:
        adj_list: dict mapping node -> list of neighbors
        start: starting node
        end: ending node

    Returns:
        list: shortest path as list of nodes, or None if no path exists
    """
    if not adj_list:
        return None

    if start == end:
        return [start]

    # BFS
    queue = deque([(start, [start])])
    visited = {start}

    while queue:
        node, path = queue.popleft()

        for neighbor in adj_list.get(node, []):
            if neighbor == end:
                return path + [neighbor]

            if neighbor not in visited:
                visited.add(neighbor)
                queue.append((neighbor, path + [neighbor]))

    return None


def topological_sort(adj_list):
    """
    Return topological ordering of a DAG, or None if cycle exists.

    Args:
        adj_list: dict mapping node -> list of neighbors

    Returns:
        list: topological ordering of nodes, or None if cycle exists
    """
    if not adj_list:
        return []

    # Use Kahn's algorithm with in-degree count
    in_degree = {node: 0 for node in adj_list}

    # Calculate in-degrees
    for node in adj_list:
        for neighbor in adj_list[node]:
            if neighbor not in in_degree:
                in_degree[neighbor] = 0
            in_degree[neighbor] += 1

    # Queue of nodes with no incoming edges
    queue = deque([node for node in in_degree if in_degree[node] == 0])
    result = []

    while queue:
        node = queue.popleft()
        result.append(node)

        for neighbor in adj_list.get(node, []):
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    # If we didn't process all nodes, there's a cycle
    if len(result) != len(in_degree):
        return None

    return result

