import pytest
from csv_parser import parse_csv, to_csv


class TestParseCSV:
    """Test parse_csv function"""

    def test_simple_csv(self):
        """Test parsing simple CSV with no special characters"""
        text = "name,age,city\nAlice,30,NYC\nBob,25,LA"
        result = parse_csv(text)
        assert result == [
            {'name': 'Alice', 'age': '30', 'city': 'NYC'},
            {'name': 'Bob', 'age': '25', 'city': 'LA'}
        ]

    def test_single_record(self):
        """Test parsing CSV with single data record"""
        text = "name,age\nAlice,30"
        result = parse_csv(text)
        assert result == [{'name': 'Alice', 'age': '30'}]

    def test_empty_fields(self):
        """Test parsing CSV with empty fields"""
        text = "name,age,city\nAlice,30,\nBob,,LA"
        result = parse_csv(text)
        assert result == [
            {'name': 'Alice', 'age': '30', 'city': ''},
            {'name': 'Bob', 'age': '', 'city': 'LA'}
        ]

    def test_quoted_fields_with_commas(self):
        """Test parsing CSV with quoted fields containing commas"""
        text = 'name,description\nAlice,"engineer, senior"\nBob,"designer, junior"'
        result = parse_csv(text)
        assert result == [
            {'name': 'Alice', 'description': 'engineer, senior'},
            {'name': 'Bob', 'description': 'designer, junior'}
        ]

    def test_quoted_fields_with_newlines(self):
        """Test parsing CSV with quoted fields containing newlines"""
        text = 'name,bio\nAlice,"line1\nline2"\nBob,"single line"'
        result = parse_csv(text)
        assert result == [
            {'name': 'Alice', 'bio': 'line1\nline2'},
            {'name': 'Bob', 'bio': 'single line'}
        ]

    def test_escaped_quotes_in_quoted_fields(self):
        """Test parsing CSV with escaped quotes (double quotes) in quoted fields"""
        text = 'name,quote\nAlice,"She said ""hello"""\nBob,"A ""quoted"" word"'
        result = parse_csv(text)
        assert result == [
            {'name': 'Alice', 'quote': 'She said "hello"'},
            {'name': 'Bob', 'quote': 'A "quoted" word'}
        ]

    def test_quoted_empty_field(self):
        """Test parsing CSV with quoted empty field"""
        text = 'name,age,city\nAlice,30,""\nBob,25,LA'
        result = parse_csv(text)
        assert result == [
            {'name': 'Alice', 'age': '30', 'city': ''},
            {'name': 'Bob', 'age': '25', 'city': 'LA'}
        ]

    def test_all_quoted_fields(self):
        """Test parsing CSV where all fields are quoted"""
        text = '"name","age","city"\n"Alice","30","NYC"\n"Bob","25","LA"'
        result = parse_csv(text)
        assert result == [
            {'name': 'Alice', 'age': '30', 'city': 'NYC'},
            {'name': 'Bob', 'age': '25', 'city': 'LA'}
        ]

    def test_mixed_quoted_and_unquoted(self):
        """Test parsing CSV with mix of quoted and unquoted fields"""
        text = 'name,description,age\nAlice,"engineer, senior",30\nBob,designer,25'
        result = parse_csv(text)
        assert result == [
            {'name': 'Alice', 'description': 'engineer, senior', 'age': '30'},
            {'name': 'Bob', 'description': 'designer', 'age': '25'}
        ]

    def test_trailing_newline(self):
        """Test parsing CSV with trailing newline"""
        text = "name,age\nAlice,30\nBob,25\n"
        result = parse_csv(text)
        assert result == [
            {'name': 'Alice', 'age': '30'},
            {'name': 'Bob', 'age': '25'}
        ]

    def test_single_column(self):
        """Test parsing CSV with single column"""
        text = "name\nAlice\nBob\nCharlie"
        result = parse_csv(text)
        assert result == [
            {'name': 'Alice'},
            {'name': 'Bob'},
            {'name': 'Charlie'}
        ]

    def test_whitespace_in_fields(self):
        """Test parsing CSV with whitespace in fields"""
        text = "name,city\n Alice , NYC \nBob,LA"
        result = parse_csv(text)
        assert result == [
            {'name': ' Alice ', 'city': ' NYC '},
            {'name': 'Bob', 'city': 'LA'}
        ]

    def test_quoted_field_with_leading_trailing_spaces(self):
        """Test that spaces inside quotes are preserved"""
        text = 'name,description\nAlice," spaces inside "\nBob,"normal"'
        result = parse_csv(text)
        assert result == [
            {'name': 'Alice', 'description': ' spaces inside '},
            {'name': 'Bob', 'description': 'normal'}
        ]


class TestToCSV:
    """Test to_csv function"""

    def test_simple_records(self):
        """Test converting simple records to CSV"""
        records = [
            {'name': 'Alice', 'age': '30', 'city': 'NYC'},
            {'name': 'Bob', 'age': '25', 'city': 'LA'}
        ]
        result = to_csv(records)
        assert result == "name,age,city\nAlice,30,NYC\nBob,25,LA"

    def test_with_explicit_columns(self):
        """Test to_csv with explicit columns parameter"""
        records = [
            {'name': 'Alice', 'age': '30', 'city': 'NYC'},
            {'name': 'Bob', 'age': '25', 'city': 'LA'}
        ]
        result = to_csv(records, columns=['name', 'city', 'age'])
        assert result == "name,city,age\nAlice,NYC,30\nBob,LA,25"

    def test_empty_fields(self):
        """Test to_csv with empty fields"""
        records = [
            {'name': 'Alice', 'age': '30', 'city': ''},
            {'name': 'Bob', 'age': '', 'city': 'LA'}
        ]
        result = to_csv(records)
        assert result == "name,age,city\nAlice,30,\nBob,,LA"

    def test_fields_with_commas(self):
        """Test to_csv with fields containing commas"""
        records = [
            {'name': 'Alice', 'description': 'engineer, senior'},
            {'name': 'Bob', 'description': 'designer, junior'}
        ]
        result = to_csv(records)
        assert result == 'name,description\nAlice,"engineer, senior"\nBob,"designer, junior"'

    def test_fields_with_quotes(self):
        """Test to_csv with fields containing quotes"""
        records = [
            {'name': 'Alice', 'quote': 'She said "hello"'},
            {'name': 'Bob', 'quote': 'A "quoted" word'}
        ]
        result = to_csv(records)
        assert result == 'name,quote\nAlice,"She said ""hello"""\nBob,"A ""quoted"" word"'

    def test_fields_with_newlines(self):
        """Test to_csv with fields containing newlines"""
        records = [
            {'name': 'Alice', 'bio': 'line1\nline2'},
            {'name': 'Bob', 'bio': 'single line'}
        ]
        result = to_csv(records)
        assert result == 'name,bio\nAlice,"line1\nline2"\nBob,"single line"'

    def test_single_record(self):
        """Test to_csv with single record"""
        records = [{'name': 'Alice', 'age': '30'}]
        result = to_csv(records)
        assert result == "name,age\nAlice,30"

    def test_single_column(self):
        """Test to_csv with single column"""
        records = [
            {'name': 'Alice'},
            {'name': 'Bob'},
            {'name': 'Charlie'}
        ]
        result = to_csv(records)
        assert result == "name\nAlice\nBob\nCharlie"

    def test_empty_records_list(self):
        """Test to_csv with empty records list"""
        records = []
        result = to_csv(records)
        assert result == ""

    def test_multiple_special_characters(self):
        """Test to_csv with fields containing multiple special characters"""
        records = [
            {'name': 'Alice', 'text': 'comma, quote" and\nnewline'},
        ]
        result = to_csv(records)
        assert result == 'name,text\nAlice,"comma, quote"" and\nnewline"'


class TestRoundTrip:
    """Test parsing and converting back maintains data integrity"""

    def test_roundtrip_simple(self):
        """Test that parse -> to_csv -> parse maintains data"""
        original = "name,age,city\nAlice,30,NYC\nBob,25,LA"
        parsed = parse_csv(original)
        converted = to_csv(parsed)
        reparsed = parse_csv(converted)
        assert parsed == reparsed

    def test_roundtrip_with_special_chars(self):
        """Test roundtrip with special characters"""
        records = [
            {'name': 'Alice', 'description': 'engineer, senior'},
            {'name': 'Bob', 'quote': 'She said "hello"'},
            {'name': 'Charlie', 'bio': 'line1\nline2'}
        ]
        csv_text = to_csv(records)
        parsed = parse_csv(csv_text)
        assert parsed == records

    def test_roundtrip_with_empty_fields(self):
        """Test roundtrip with empty fields"""
        records = [
            {'name': 'Alice', 'age': '30', 'city': ''},
            {'name': 'Bob', 'age': '', 'city': 'LA'}
        ]
        csv_text = to_csv(records)
        parsed = parse_csv(csv_text)
        assert parsed == records

